# Catalog module defining LibraryItem hierarchy
# Demonstrates abstract base classes and inheritance

@abstract
class LibraryItem:
    title: str
    year: int

    def __init__(self, title: str, year: int):
        self.title = title
        self.year = year

    @abstract
    def format_info(self) -> str:
        ...

    def get_age(self, current_year: int) -> int:
        return current_year - self.year


class Book(LibraryItem):
    author: str
    pages: int

    def __init__(self, title: str, author: str, year: int, pages: int):
        super().__init__(title, year)
        self.author = author
        self.pages = pages

    @override
    def format_info(self) -> str:
        return f"'{self.title}' by {self.author} ({self.year})"


class Magazine(LibraryItem):
    issue_number: int
    publisher: str

    def __init__(self, title: str, publisher: str, year: int, issue_number: int):
        super().__init__(title, year)
        self.publisher = publisher
        self.issue_number = issue_number

    @override
    def format_info(self) -> str:
        return f"{self.title} #{self.issue_number} ({self.publisher})"

    @override
    def get_age(self, current_year: int) -> int:
        if self.year == current_year:
            return 0
        return super().get_age(current_year)

