# Library module providing base classes for a library management system
# Demonstrates classes with inheritance that can be imported
from catalog import Book, Magazine


class Library:
    name: str
    books: list[Book]
    magazines: list[Magazine]

    def __init__(self, name: str):
        self.name = name
        self.books = []
        self.magazines = []

    def add_book(self, book: Book) -> None:
        self.books.append(book)

    def add_magazine(self, mag: Magazine) -> None:
        self.magazines.append(mag)

    def item_count(self) -> int:
        return len(self.books) + len(self.magazines)

    def get_catalog_summary(self) -> str:
        result: str = f"Library '{self.name}' contains:\n"
        result = result + f"  Books: {len(self.books)}\n"
        result = result + f"  Magazines: {len(self.magazines)}"
        return result
